import React, { useState } from 'react';
const CATEGORIES = [
  {
    id: 'frontend',
    label: 'Frontend',
    skills: [
      { name: 'React / Next.js',  level: 92 },
      { name: 'JavaScript (ES6+)',level: 90 },
      { name: 'HTML & CSS',       level: 95 },
      { name: 'TypeScript',       level: 78 },
      { name: 'Redux / Zustand',  level: 80 },
    ],
  },
  {
    id: 'backend',
    label: 'Backend',
    skills: [
      { name: 'Node.js / Express', level: 85 },
      { name: 'Python / Django',   level: 75 },
      { name: 'REST & GraphQL',    level: 82 },
      { name: 'PostgreSQL',        level: 78 },
      { name: 'MongoDB',           level: 72 },
    ],
  },
  {
    id: 'tools',
    label: 'Tools & DevOps',
    skills: [
      { name: 'Git & GitHub',  level: 90 },
      { name: 'Docker',        level: 70 },
      { name: 'AWS (basics)',  level: 65 },
      { name: 'CI/CD',         level: 68 },
      { name: 'Figma',         level: 75 },
    ],
  },
];

const TECH_LOGOS = [
  'React','Node.js','Python','PostgreSQL','MongoDB',
  'Docker','AWS','Figma','Git','TypeScript',
];

function SkillBar({ name, level, index }) {
  return (
    <div className="skill-bar" style={{ animationDelay: `${index * 0.07}s` }}>
      <div className="skill-bar__header">
        <span className="skill-bar__name">{name}</span>
        <span className="skill-bar__pct">{level}%</span>
      </div>
      <div className="skill-bar__track">
        <div
          className="skill-bar__fill"
          style={{ '--target-width': `${level}%` }}
        />
      </div>
    </div>
  );
}

function Skills() {
  const [active, setActive] = useState('frontend');
  const category = CATEGORIES.find(c => c.id === active);

  return (
    <section id="skills" className="skills">
      <div className="container">
        <p className="section-tag">What I know</p>
        <h2 className="section-title">Skills &amp; Technologies</h2>

        {/* Tab pills */}
        <div className="skills__tabs" role="tablist">
          {CATEGORIES.map(cat => (
            <button
              key={cat.id}
              role="tab"
              aria-selected={active === cat.id}
              className={`skills__tab ${active === cat.id ? 'skills__tab--active' : ''}`}
              onClick={() => setActive(cat.id)}
            >
              {cat.label}
            </button>
          ))}
        </div>

        {/* Skill bars */}
        <div className="skills__bars" key={active}>
          {category.skills.map((skill, i) => (
            <SkillBar key={skill.name} {...skill} index={i} />
          ))}
        </div>

        {/* Tech cloud */}
        <div className="skills__cloud">
          <p className="skills__cloud-label">Also worked with</p>
          <div className="skills__cloud-tags">
            {TECH_LOGOS.map(t => (
              <span key={t} className="skills__tag">{t}</span>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}

export default Skills;
